package com.bank.app.transaction;

import android.content.Context;
import android.security.keystore.KeyGenParameterSpec;
import android.security.keystore.KeyProperties;
import androidx.security.crypto.EncryptedSharedPreferences;
import androidx.security.crypto.MasterKey;
import java.security.KeyStore;
import java.util.UUID;
import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import javax.crypto.spec.GCMParameterSpec;

public class SecureTransactionManager {
    private static final String KEYSTORE_ALIAS = "BankTransactionKey";
    private static final String PREFS_NAME = "secure_transaction_prefs";
    private static final int MIN_INTEGRITY_SCORE = 50;
    
    private Context context;
    private DeviceIntegrityChecker integrityChecker;
    private EncryptedSharedPreferences encryptedPrefs;
    
    public SecureTransactionManager(Context context) throws Exception {
        this.context = context;
        this.integrityChecker = new DeviceIntegrityChecker(context);
        initializeSecureStorage();
    }
    
    private void initializeSecureStorage() throws Exception {
        MasterKey masterKey = new MasterKey.Builder(context)
            .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
            .build();
        
        encryptedPrefs = (EncryptedSharedPreferences) EncryptedSharedPreferences.create(
            context,
            PREFS_NAME,
            masterKey,
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        );
    }
    
    public TransactionResult processTransaction(Transaction transaction) throws Exception {
        DeviceIntegrityChecker.DeviceIntegrityResult integrityResult = 
            integrityChecker.checkDeviceIntegrity();
        
        if (integrityResult.isHighRisk()) {
            return new TransactionResult(
                false, 
                "Transaction blocked: Device integrity check failed. Please contact support.",
                TransactionResult.ErrorCode.DEVICE_INTEGRITY_FAILED
            );
        }
        
        if (integrityResult.isMediumRisk()) {
            if (!performAdditionalVerification(transaction)) {
                return new TransactionResult(
                    false,
                    "Additional verification required. Please complete enhanced authentication.",
                    TransactionResult.ErrorCode.ADDITIONAL_VERIFICATION_REQUIRED
                );
            }
        }
        
        if (!validateTransaction(transaction)) {
            return new TransactionResult(
                false,
                "Transaction validation failed",
                TransactionResult.ErrorCode.VALIDATION_FAILED
            );
        }
        
        String encryptedData = encryptTransactionData(transaction);
        
        boolean success = executeSecureTransaction(encryptedData, integrityResult);
        
        if (success) {
            logSecureTransaction(transaction, integrityResult);
            return new TransactionResult(
                true,
                "Transaction completed successfully",
                TransactionResult.ErrorCode.NONE
            );
        } else {
            return new TransactionResult(
                false,
                "Transaction processing failed",
                TransactionResult.ErrorCode.PROCESSING_FAILED
            );
        }
    }
    
    private boolean performAdditionalVerification(Transaction transaction) {
        return transaction.hasSecondFactorAuth && 
               transaction.hasBiometricAuth &&
               transaction.verificationCode != null;
    }
    
    private boolean validateTransaction(Transaction transaction) {
        if (transaction.amount <= 0) return false;
        if (transaction.fromAccount == null || transaction.toAccount == null) return false;
        if (transaction.amount > transaction.dailyLimit) return false;
        return true;
    }
    
    private String encryptTransactionData(Transaction transaction) throws Exception {
        KeyStore keyStore = KeyStore.getInstance("AndroidKeyStore");
        keyStore.load(null);
        
        if (!keyStore.containsAlias(KEYSTORE_ALIAS)) {
            KeyGenerator keyGenerator = KeyGenerator.getInstance(
                KeyProperties.KEY_ALGORITHM_AES, "AndroidKeyStore");
            
            KeyGenParameterSpec keyGenParameterSpec = new KeyGenParameterSpec.Builder(
                KEYSTORE_ALIAS,
                KeyProperties.PURPOSE_ENCRYPT | KeyProperties.PURPOSE_DECRYPT)
                .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
                .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
                .setUserAuthenticationRequired(false)
                .build();
            
            keyGenerator.init(keyGenParameterSpec);
            keyGenerator.generateKey();
        }
        
        SecretKey secretKey = (SecretKey) keyStore.getKey(KEYSTORE_ALIAS, null);
        Cipher cipher = Cipher.getInstance("AES/GCM/NoPadding");
        cipher.init(Cipher.ENCRYPT_MODE, secretKey);
        
        byte[] iv = cipher.getIV();
        byte[] encrypted = cipher.doFinal(transaction.toJson().getBytes());
        
        return android.util.Base64.encodeToString(iv, android.util.Base64.DEFAULT) + ":" +
               android.util.Base64.encodeToString(encrypted, android.util.Base64.DEFAULT);
    }
    
    private boolean executeSecureTransaction(String encryptedData, 
                                            DeviceIntegrityChecker.DeviceIntegrityResult integrityResult) {
        String transactionId = UUID.randomUUID().toString();
        
        encryptedPrefs.edit()
            .putString("last_transaction_id", transactionId)
            .putString("last_transaction_data", encryptedData)
            .putInt("device_integrity_score", integrityResult.overallIntegrity)
            .putLong("transaction_timestamp", System.currentTimeMillis())
            .apply();
        
        return true;
    }
    
    private void logSecureTransaction(Transaction transaction, 
                                      DeviceIntegrityChecker.DeviceIntegrityResult integrityResult) {
        String logEntry = String.format(
            "Transaction: %s, Amount: %.2f, Integrity: %d, Timestamp: %d",
            transaction.transactionId,
            transaction.amount,
            integrityResult.overallIntegrity,
            System.currentTimeMillis()
        );
        
        encryptedPrefs.edit()
            .putString("transaction_log_" + System.currentTimeMillis(), logEntry)
            .apply();
    }
    
    public static class Transaction {
        public String transactionId;
        public String fromAccount;
        public String toAccount;
        public double amount;
        public double dailyLimit;
        public boolean hasSecondFactorAuth;
        public boolean hasBiometricAuth;
        public String verificationCode;
        
        public String toJson() {
            return String.format(
                "{\"id\":\"%s\",\"from\":\"%s\",\"to\":\"%s\",\"amount\":%.2f}",
                transactionId, fromAccount, toAccount, amount
            );
        }
    }
    
    public static class TransactionResult {
        public boolean success;
        public String message;
        public ErrorCode errorCode;
        
        public TransactionResult(boolean success, String message, ErrorCode errorCode) {
            this.success = success;
            this.message = message;
            this.errorCode = errorCode;
        }
        
        public enum ErrorCode {
            NONE,
            DEVICE_INTEGRITY_FAILED,
            ADDITIONAL_VERIFICATION_REQUIRED,
            VALIDATION_FAILED,
            PROCESSING_FAILED
        }
    }
}

package com.bank.app.transaction;

import android.content.Context;
import android.os.Handler;
import android.os.Looper;
import androidx.security.crypto.EncryptedSharedPreferences;
import androidx.security.crypto.MasterKey;
import java.text.NumberFormat;
import java.util.Locale;

public class AccountBalanceManager {
    private static final String PREFS_NAME = "secure_account_prefs";
    private static final int BALANCE_REFRESH_INTERVAL = 30000;
    
    private Context context;
    private DeviceIntegrityChecker integrityChecker;
    private EncryptedSharedPreferences encryptedPrefs;
    private Handler handler;
    
    public AccountBalanceManager(Context context) throws Exception {
        this.context = context;
        this.integrityChecker = new DeviceIntegrityChecker(context);
        this.handler = new Handler(Looper.getMainLooper());
        initializeSecureStorage();
    }
    
    private void initializeSecureStorage() throws Exception {
        MasterKey masterKey = new MasterKey.Builder(context)
            .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
            .build();
        
        encryptedPrefs = (EncryptedSharedPreferences) EncryptedSharedPreferences.create(
            context,
            PREFS_NAME,
            masterKey,
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        );
    }
    
    public BalanceResult getAccountBalance(String accountId) {
        DeviceIntegrityChecker.DeviceIntegrityResult integrityResult = 
            integrityChecker.checkDeviceIntegrity();
        
        if (integrityResult.isHighRisk()) {
            return new BalanceResult(
                false,
                0.0,
                "Balance unavailable: Device security check failed",
                true
            );
        }
        
        if (integrityResult.isMediumRisk()) {
            return new BalanceResult(
                true,
                getObfuscatedBalance(accountId),
                "Limited balance view - Enhanced security active",
                true
            );
        }
        
        double balance = getSecureBalance(accountId);
        
        return new BalanceResult(
            true,
            balance,
            "Balance retrieved successfully",
            false
        );
    }
    
    private double getSecureBalance(String accountId) {
        String balanceKey = "balance_" + accountId;
        String balanceStr = encryptedPrefs.getString(balanceKey, "0.0");
        
        try {
            return Double.parseDouble(balanceStr);
        } catch (NumberFormatException e) {
            return 0.0;
        }
    }
    
    private double getObfuscatedBalance(String accountId) {
        double actualBalance = getSecureBalance(accountId);
        return Math.round(actualBalance / 100.0) * 100.0;
    }
    
    public void updateBalance(String accountId, double newBalance) throws Exception {
        DeviceIntegrityChecker.DeviceIntegrityResult integrityResult = 
            integrityChecker.checkDeviceIntegrity();
        
        if (integrityResult.isHighRisk()) {
            throw new SecurityException("Balance update blocked: Device integrity compromised");
        }
        
        String balanceKey = "balance_" + accountId;
        encryptedPrefs.edit()
            .putString(balanceKey, String.valueOf(newBalance))
            .putLong("balance_updated_" + accountId, System.currentTimeMillis())
            .putInt("integrity_score_" + accountId, integrityResult.overallIntegrity)
            .apply();
    }
    
    public String formatBalance(double balance, boolean obfuscate) {
        if (obfuscate) {
            return "≈ " + NumberFormat.getCurrencyInstance(Locale.US).format(balance);
        }
        return NumberFormat.getCurrencyInstance(Locale.US).format(balance);
    }
    
    public static class BalanceResult {
        public boolean success;
        public double balance;
        public String message;
        public boolean isRestricted;
        
        public BalanceResult(boolean success, double balance, String message, boolean isRestricted) {
            this.success = success;
            this.balance = balance;
            this.message = message;
            this.isRestricted = isRestricted;
        }
    }
}